# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import java.nio.file.{Files, Path, Paths}
import scala.util.{Try, Using}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    // Resolve and normalize the requested path to prevent path traversal
    val requestedPath: Path = uploadsDir.resolve(filename).toAbsolutePath.normalize()

    // SECURITY: Ensure the resolved path is still within the uploads directory
    if (!requestedPath.startsWith(uploadsDir)) {
      Forbidden("Access denied: path traversal detected")
    } else if (!Files.exists(requestedPath)) {
      NotFound(s"File not found: $filename")
    } else if (!Files.isRegularFile(requestedPath)) {
      BadRequest("Requested path is not a regular file")
    } else if (!Files.isReadable(requestedPath)) {
      Forbidden("File is not readable")
    } else {
      // Detect content type based on file extension
      val contentType: String = Option(Files.probeContentType(requestedPath))
        .getOrElse("application/octet-stream")

      val fileContent: Try[String] = Using(scala.io.Source.fromFile(requestedPath.toFile)("UTF-8")) { source =>
        source.mkString
      }

      fileContent match {
        case scala.util.Success(content) =>
          Ok(content).as(contentType)
        case scala.util.Failure(exception) =>
          InternalServerError(s"Error reading file: ${exception.getMessage}")
      }
    }
  }

  def listFiles(subdirectory: Option[String]): Action[AnyContent] = Action { implicit request =>
    val targetDir: Path = subdirectory match {
      case Some(sub) => uploadsDir.resolve(sub).toAbsolutePath.normalize()
      case None      => uploadsDir
    }

    // SECURITY: Ensure the resolved path is still within the uploads directory
    if (!targetDir.startsWith(uploadsDir)) {
      Forbidden("Access denied: path traversal detected")
    } else if (!Files.exists(targetDir) || !Files.isDirectory(targetDir)) {
      NotFound("Directory not found")
    } else {
      val files = Files.list(targetDir).toArray.map { path =>
        val p = path.asInstanceOf[Path]
        val relativePath = uploadsDir.relativize(p).toString
        val isDir = Files.isDirectory(p)
        s"""{"name": "${p.getFileName}", "path": "$relativePath", "isDirectory": $isDir}"""
      }

      Ok(s"""{"files": [${files.mkString(",")}]}""").as("application/json")
    }
  }

  def serveBinaryFile(filename: String): Action[AnyContent] = Action { implicit request =>
    val requestedPath: Path = uploadsDir.resolve(filename).toAbsolutePath.normalize()

    // SECURITY: Ensure the resolved path is still within the uploads directory
    if (!requestedPath.startsWith(uploadsDir)) {
      Forbidden("Access denied: path traversal detected")
    } else if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
      NotFound(s"File not found: $filename")
    } else {
      val contentType: String = Option(Files.probeContentType(requestedPath))
        .getOrElse("application/octet-stream")

      Ok.sendPath(requestedPath, inline = true)
        .as(contentType)
        .withHeaders(
          "Content-Disposition" -> s"""inline; filename="${requestedPath.getFileName}""""
        )
    }
  }
}